#include <ctime>
#include <iostream>

int main() {
    std::time_t now = std::time(nullptr);
    std::tm* local = std::localtime(&now);

    // tm_year: عدد السنوات منذ 1900، لذلك نضيف 1900
    std::cout << "Year: " << (local->tm_year + 1900) << '\n';

    // tm_mon: 0 = يناير، 11 = ديسمبر، لذلك نضيف 1
    std::cout << "Month: " << (local->tm_mon + 1) << '\n';

    // tm_mday: يوم الشهر يبدأ من 1 (بدون انزياح)
    std::cout << "Day: " << local->tm_mday << '\n';

    // tm_hour, tm_min, tm_sec: تبدأ من 0 مباشرة
    std::cout << "Time: " << local->tm_hour << ':' << local->tm_min << ':' << local->tm_sec << '\n';
}

