#include <ctime>
#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::vector<int> data(100000);
    for (auto& v : data) v = rand();

    std::clock_t start = std::clock();
    std::sort(data.begin(), data.end());
    std::clock_t end = std::clock();

    // قسمة على CLOCKS_PER_SEC لتحويل من ticks إلى ثوانٍ
    double seconds = double(end - start) / CLOCKS_PER_SEC;
    std::cout << "Sort took " << seconds << " CPU seconds\n";
}

#include <ctime>
#include <iostream>

void simulate_user_wait() {
    // هذا الانتظار لا يستهلك CPU، فلا يُحتسب في clock
    volatile int dummy = 0;
    for (int i = 0; i < 1000; ++i) dummy += i;
}

int main() {
    std::clock_t cpu_start = std::clock();
    simulate_user_wait();
    std::clock_t cpu_end = std::clock();

    std::time_t wall_start = std::time(nullptr);
    // لو كان هنا انتظار حقيقي مثل sleep أو إدخال مستخدم
    // لاختلف الفارق جذريًا بين clock و time
    simulate_user_wait();
