#include <algorithm>
#include <iostream>

int main() {
    // مقارنة بسيطة
    std::cout << std::max(3, 7) << '\n'; // 7

    // مع قيمة أولية (C++11)
    std::cout << std::max({1, 5, 3, 9, 2}) << '\n'; // 9

    // مع مقارنة مخصصة
    std::cout << std::max(3, 7, std::greater<int>()) << '\n'; // 7

    // تطبيق عملي: تحديد حجم المخزن
    int needed = 50;
    int capacity = std::max(needed, 64); // 64 (الحد الأدنى 64)
    std::cout << capacity << '\n';
}

#include <algorithm>
#include <iostream>

int main() {
    int a = -1;
    unsigned int b = 1;

    // ⚠️ قد لا تعمل كما تتوقع!
    // a يُحوّل إلى unsigned: -1 يصبح 4294967295
    auto result = std::max(a, b);
    std::cout << result << '\n'; // 4294967295 (ليس 1!)

    // ✅ الحل: تحويل صريح
    auto safe = std::max(static_cast<int>(a), static_cast<int>(b));
    std::cout << safe << '\n'; // 1
}

